    @fore = Forecast.create(zip_code: "01247",
                            current: JSON.parse(@current_json),
                            extended: JSON.parse(@extended_json))
  end

  test "valid forecast record" do
    assert @fore.persisted?
    assert @fore.current
    assert @fore.extended
  end

  test "current_weather parsed from api" do
    current_weather = @fore.current_weather
    assert_not_nil current_weather
    temp = @fore.current_weather.dig("temp")
    raw_temp = JSON.parse(@current_json).dig("main", "temp")
    assert_equal raw_temp, temp
  end

  test "five_day_forecast parsed from api" do
    fdf = @fore.five_day_forecast
    assert_not_nil fdf
    assert_equal 40, fdf.length
  end

  test "sunrise and sunset from api" do
    sun_data = @fore.sun
    raw_sunrise = JSON.parse(@current_json).dig("sys", "sunrise")
    assert_equal Time.zone.parse(raw_sunrise)&.localtime&.strftime("%I:%M %p"), sun_data.rise
    raw_sunset = JSON.parse(@current_json).dig("sys", "sunset")
    assert_equal Time.zone.parse(raw_sunset)&.localtime&.strftime("%I:%M %p"), sun_data.set
  end

  test "organizes data for tabular display" do
    tabs = @fore.tabular_forecast
    assert_equal [ :days, :times, :data ].sort, tabs.keys.sort
  end
end
